def gen(rng, size):
    n = max(1, min(size, 20000))
    target = rng.randint(1, 6)
    tops = []
    bottoms = []
    for _ in range(n):
        other = rng.randint(1, 6)
        if rng.random() < 0.5:
            tops.append(target)
            bottoms.append(other)
        else:
            tops.append(other)
            bottoms.append(target)
    if rng.random() < 0.3:
        i = rng.randint(0, n - 1)
        v = rng.randint(1, 6)
        if v != target:
            tops[i] = v
            bottoms[i] = v
    return [tops, bottoms]

