class Solution:
    def minDominoRotations(self, tops, bottoms):
        n = len(tops)
        best = -1
        for target in range(1, 7):
            ok = True
            top_rot = 0
            bot_rot = 0
            for i in range(n):
                if tops[i] != target and bottoms[i] != target:
                    ok = False
                    break
                if tops[i] != target:
                    top_rot += 1
                if bottoms[i] != target:
                    bot_rot += 1
            if ok:
                cand = min(top_rot, bot_rot)
                if best == -1 or cand < best:
                    best = cand
        return best

