class Solution:
    def minDominoRotations(self, tops, bottoms):
        n = len(tops)
        def check(target):
            rot_top = rot_bot = 0
            for i in range(n):
                if tops[i] != target and bottoms[i] != target:
                    return -1
                if tops[i] != target:
                    rot_top += 1
                elif bottoms[i] != target:
                    rot_bot += 1
            return min(rot_top, rot_bot)
        a = check(tops[0])
        if a != -1:
            return a
        return check(bottoms[0])

